import React, { useState, useEffect } from "react";
import { motion, AnimatePresence } from "framer-motion";

const GOLD = "#C9A84C";
const GOLD_LIGHT = "#E8C96A";
const BG = "#080808";
const SURFACE = "#111111";
const BORDER = "rgba(201,168,76,0.18)";

const fade = (delay = 0) => ({
  initial: { opacity: 0, y: 28 },
  animate: { opacity: 1, y: 0 },
  transition: { duration: 0.65, delay, ease: [0.22, 1, 0.36, 1] },
});

const inView = {
  initial: { opacity: 0, y: 32 },
  whileInView: { opacity: 1, y: 0 },
  viewport: { once: true, margin: "-60px" },
  transition: { duration: 0.65, ease: [0.22, 1, 0.36, 1] },
};

export default function MapleLuxeSite() {
  const [menuOpen, setMenuOpen] = useState(false);
  const [scrolled, setScrolled] = useState(false);
  const [showTop, setShowTop] = useState(false);
  const [formStatus, setFormStatus] = useState(null);
  const [files, setFiles] = useState([]);
  const [activeService, setActiveService] = useState(0);

  useEffect(() => {
    const onScroll = () => {
      setScrolled(window.scrollY > 20);
      setShowTop(window.scrollY > 500);
    };
    window.addEventListener("scroll", onScroll);
    return () => window.removeEventListener("scroll", onScroll);
  }, []);

  const handleSubmit = async (e) => {
    e.preventDefault();
    try {
      await fetch("https://formsubmit.co/ajax/mapleluxebookings@gmail.com", {
        method: "POST",
        body: new FormData(e.target),
      });
      setFormStatus("success");
      e.target.reset();
      setFiles([]);
    } catch {
      setFormStatus("error");
    }
    setTimeout(() => setFormStatus(null), 6000);
  };

  const services = [
    {
      title: "Fencing & Decking",
      short: "Fencing",
      desc: "Custom wood, composite and vinyl builds engineered for Calgary's brutal freeze-thaw cycles. Every post set in concrete, every board precision-cut.",
      features: ["Cedar, composite & vinyl options", "Concrete footings to frost depth", "Permit-ready drawings included", "10-year workmanship warranty"],
      img: "https://images.unsplash.com/photo-1621905251918-48416bd8575a?auto=format&fit=crop&w=900&q=80",
      icon: "▤",
    },
    {
      title: "Landscaping & Hardscapes",
      short: "Landscaping",
      desc: "Full-service design, install and year-round maintenance. Retaining walls, patios, irrigation and outdoor lighting that turn your yard into an asset.",
      features: ["3D design renders before we break ground", "Segmental retaining walls", "Smart irrigation systems", "LED landscape lighting"],
      img: "https://images.unsplash.com/photo-1557428887-5611a52a6f3a?auto=format&fit=crop&w=900&q=80",
      icon: "✦",
    },
    {
      title: "Property Management",
      short: "Management",
      desc: "We handle tenants, inspections, financials and compliance so you collect rent without the headaches. Transparent owner portal, monthly reporting.",
      features: ["Tenant screening & placement", "24/7 emergency maintenance line", "Monthly financial statements", "Annual property inspections"],
      img: "https://images.unsplash.com/photo-1560448204-e02f11c3d0e2?auto=format&fit=crop&w=900&q=80",
      icon: "◈",
    },
    {
      title: "Custom Design Build",
      short: "Design Build",
      desc: "Concept to completion under one roof. We design, permit and build your outdoor living space — pergolas, outdoor kitchens, fire features and more.",
      features: ["In-house design & engineering", "Full permit coordination", "Outdoor kitchens & fire pits", "Pergolas & covered structures"],
      img: "https://images.unsplash.com/photo-1534237710431-e2a6981d3f9a?auto=format&fit=crop&w=900&q=80",
      icon: "◇",
    },
    {
      title: "Maintenance & Repairs",
      short: "Maintenance",
      desc: "Seasonal programs that protect your investment year-round. Spring start-up to winter shutdown — plus 24/7 emergency response when it matters most.",
      features: ["Spring & fall programs", "24/7 emergency dispatch", "Preventative maintenance plans", "Licensed trades on every call"],
      img: "https://images.unsplash.com/photo-1581147036324-c6c2f01b2cfa?auto=format&fit=crop&w=900&q=80",
      icon: "⚙",
    },
    {
      title: "Cleaning & Turnover",
      short: "Cleaning",
      desc: "Move-in/out cleans, common area maintenance and deep clean crews that meet property management standards. Spotless, every time, on time.",
      features: ["Move-in / move-out cleans", "Common area maintenance", "Post-construction cleanup", "Same-day availability"],
      img: "https://images.unsplash.com/photo-1581578731548-c64695cc6952?auto=format&fit=crop&w=900&q=80",
      icon: "✧",
    },
  ];

  const process = [
    { step: "01", title: "Tell Us Your Vision", body: "Fill out our 2-minute project brief or call (587) 400-4071. Upload photos if you have them — it helps us give you a more accurate quote, faster." },
    { step: "02", title: "Receive Your Detailed Quote", body: "Within 12–24 hours you'll have a line-item proposal with timeline, material options and a dedicated project lead assigned to your file." },
    { step: "03", title: "We Execute. You Enjoy.", body: "Milestone updates, owner-facing reports and a quality sign-off walkthrough at every stage. Your property, elevated — on time and on budget." },
  ];

  const testimonials = [
    { q: "MapleLuxe built our 600 sqft deck and custom fence in 8 days. The detail work is unreal — neighbours keep asking who did it. They've earned a client for life.", name: "Rachel L.", role: "Homeowner, SW Calgary", init: "RL" },
    { q: "I manage 14 rental units. Switching to MapleLuxe for property management cut my vacancy rate in half and I haven't had a maintenance crisis in over a year.", name: "Michael R.", role: "Rental Portfolio Owner", init: "MR" },
