                    onMouseLeave={e => e.currentTarget.style.borderColor = BORDER}>
                    <input type="file" id="upload" name="media" multiple accept="image/*,video/*,.pdf,.doc,.docx" style={{ display: "none" }} onChange={e => setFiles(Array.from(e.target.files))} />
