                      {files.length > 0 && (
                        <div className="mt-4 flex flex-wrap gap-2 justify-center">
                          {files.map((f, i) => (
                            <span key={i} className="px-3 py-1 rounded-full text-xs" style={{ background: "rgba(201,168,76,.12)", color: GOLD, border: `1px solid ${BORDER}` }}>
